# @cctt_verify {"v":2,"sym":"sympy.calculus.tests.test_accumulationbounds.test_AccumBounds_pow","kind":"function","src_hash":"6e6dcc0ac58ddec6","in":{"base":"Any"},"out":{"base":"Any","pred":"B(0, 2) ** 2 == B(0, 4) and B(-1, 1) ** 2 == B(0, 1) and B(1, 2) ** 2 == B(1, 4) and B(-1, 2) ** 3 == B(-1, 8) and B(-1, 1) ** 0 == 1 and B(1, 2) ** Rational(5, 2) == B(1, 4 * sqrt(2)) and B(0, 2) ** S.Half == B(0, sqrt(2)) and unchanged(Pow, B(neg, 1), S.Half) and B(nn, nn + 1) ** S.Half == B(sqrt(nn), sqrt(nn + 1)) and B(nn, nn + 1) ** nn == B(nn ** nn, (nn + 1) ** nn) and unchanged(Pow, B(nn, nn + 1), x) and B(1, 2) ** i == B(Min(1, 2 ** i), Max(1, 2 ** i)) and B(1, 2) ** i == B(1, 2 ** i) and B(0, 1) ** i == B(0 ** i, 1) and B(1, 5) ** (-2) == B(Rational(1, 25), 1) and B(-1, 3) ** (-2) == B(0, oo) and B(0, 2) ** (-3) == B(Rational(1, 8), oo) and B(-2, 0) ** (-3) == B(-oo, -Rational(1, 8)) and B(0, 2) ** (-2) == B(Rational(1, 4), oo) and B(-1, 2) ** (-3) == B(-oo, oo) and B(-3, -2) ** (-3) == B(Rational(-1, 8), Rational(-1, 27)) and B(-3, -2) ** (-2) == B(Rational(1, 9), Rational(1, 4)) and B(0, oo) ** S.Half == B(0, oo) and B(-oo, 0) ** (-2) == B(0, oo) and B(-2, 0) ** (-2) == B(Rational(1, 4), oo) and B(Rational(1, 3), S.Half) ** oo is S.Zero and B(0, S.Half) ** oo is S.Zero and B(S.Half, 1) ** oo == B(0, oo) and B(0, 1) ** oo == B(0, oo) and B(2, 3) ** oo is oo and B(1, 2) ** oo == B(0, oo) and B(S.Half, 3) ** oo == B(0, oo) and B(Rational(-1, 3), Rational(-1, 4)) ** oo is S.Zero and B(-1, Rational(-1, 2)) ** oo is S.NaN and B(-3, -2) ** oo is zoo and B(-2, -1) ** oo is S.NaN and B(-2, Rational(-1, 2)) ** oo is S.NaN and B(Rational(-1, 2), S.Half) ** oo is S.Zero and B(Rational(-1, 2), 1) ** oo == B(0, oo) and B(Rational(-2, 3), 2) ** oo == B(0, oo) and B(-1, 1) ** oo == B(-oo, oo) and B(-1, S.Half) ** oo == B(-oo, oo) and B(-1, 2) ** oo == B(-oo, oo) and B(-2, S.Half) ** oo == B(-oo, oo) and B(1, 2) ** x == Pow(B(1, 2), x, evaluate=False) and B(2, 3) ** (-oo) is S.Zero and B(0, 2) ** (-oo) == B(0, oo) and B(-1, 2) ** (-oo) == B(-oo, oo) and (tan(x) ** sin(2 * x)).subs(x, B(0, pi / 2)) == Pow(B(-oo, oo), B(0, 1))"},"spec":{"lhs":"test_AccumBounds_pow()","rhs":"test_AccumBounds_pow produces the expected output","over":{"base":"Any"},"name":"test_AccumBounds_pow_correct"},"guarantee":"test_AccumBounds_pow produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.calculus.tests.test_accumulationbounds.test_AccumBounds_pow_correct","statement":"Path(test_AccumBounds_pow(x), test_AccumBounds_pow produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"43c103d3f1d92a46"}
def test_AccumBounds_pow():
    assert B(0, 2)**2 == B(0, 4)
    assert B(-1, 1)**2 == B(0, 1)
    assert B(1, 2)**2 == B(1, 4)
    assert B(-1, 2)**3 == B(-1, 8)
    assert B(-1, 1)**0 == 1

    assert B(1, 2)**Rational(5, 2) == B(1, 4*sqrt(2))
    assert B(0, 2)**S.Half == B(0, sqrt(2))

    neg = Symbol('neg', negative=True)
    assert unchanged(Pow, B(neg, 1), S.Half)
    nn = Symbol('nn', nonnegative=True)
    assert B(nn, nn + 1)**S.Half == B(sqrt(nn), sqrt(nn + 1))
    assert B(nn, nn + 1)**nn == B(nn**nn, (nn + 1)**nn)
    assert unchanged(Pow, B(nn, nn + 1), x)
    i = Symbol('i', integer=True)
    assert B(1, 2)**i == B(Min(1, 2**i), Max(1, 2**i))
    i = Symbol('i', integer=True, nonnegative=True)
    assert B(1, 2)**i == B(1, 2**i)
    assert B(0, 1)**i == B(0**i, 1)

    assert B(1, 5)**(-2) == B(Rational(1, 25), 1)
    assert B(-1, 3)**(-2) == B(0, oo)
    assert B(0, 2)**(-3) == B(Rational(1, 8), oo)
    assert B(-2, 0)**(-3) == B(-oo, -Rational(1, 8))
    assert B(0, 2)**(-2) == B(Rational(1, 4), oo)
    assert B(-1, 2)**(-3) == B(-oo, oo)
    assert B(-3, -2)**(-3) == B(Rational(-1, 8), Rational(-1, 27))
    assert B(-3, -2)**(-2) == B(Rational(1, 9), Rational(1, 4))
    assert B(0, oo)**S.Half == B(0, oo)
    assert B(-oo, 0)**(-2) == B(0, oo)
    assert B(-2, 0)**(-2) == B(Rational(1, 4), oo)

    assert B(Rational(1, 3), S.Half)**oo is S.Zero
    assert B(0, S.Half)**oo is S.Zero
    assert B(S.Half, 1)**oo == B(0, oo)
    assert B(0, 1)**oo == B(0, oo)
    assert B(2, 3)**oo is oo
    assert B(1, 2)**oo == B(0, oo)
    assert B(S.Half, 3)**oo == B(0, oo)
    assert B(Rational(-1, 3), Rational(-1, 4))**oo is S.Zero
    assert B(-1, Rational(-1, 2))**oo is S.NaN
    assert B(-3, -2)**oo is zoo
    assert B(-2, -1)**oo is S.NaN
    assert B(-2, Rational(-1, 2))**oo is S.NaN
    assert B(Rational(-1, 2), S.Half)**oo is S.Zero
    assert B(Rational(-1, 2), 1)**oo == B(0, oo)
    assert B(Rational(-2, 3), 2)**oo == B(0, oo)
    assert B(-1, 1)**oo == B(-oo, oo)
    assert B(-1, S.Half)**oo == B(-oo, oo)
    assert B(-1, 2)**oo == B(-oo, oo)
    assert B(-2, S.Half)**oo == B(-oo, oo)

    assert B(1, 2)**x == Pow(B(1, 2), x, evaluate=False)

    assert B(2, 3)**(-oo) is S.Zero
    assert B(0, 2)**(-oo) == B(0, oo)
    assert B(-1, 2)**(-oo) == B(-oo, oo)

    assert (tan(x)**sin(2*x)).subs(x, B(0, pi/2)) == \
        Pow(B(-oo, oo), B(0, 1))


