# @cctt_verify {"v":2,"sym":"sympy.calculus.tests.test_accumulationbounds.test_AccumBounds_exponent","kind":"function","src_hash":"af6477f21a904dd5","in":{"base":"Any"},"out":{"base":"Any","pred":"z.subs(a, 0) == B(0, 1) and z.subs(a, 1) == 0 and p.is_Pow and p.args == (0, B(-1, -S.Half)) and 1 ** B(a, a + 1) == 1 and S.Half ** B(-2, 2) == B(S(1) / 4, 4) and 2 ** B(-2, 2) == B(S(1) / 4, 4) and B(0, 1) ** B(S(1) / 2, 1) == B(0, 1) and B(0, 1) ** B(0, 1) == B(0, 1) and B(2, 3) ** B(-3, -2) == B(S(1) / 27, S(1) / 4) and B(2, 3) ** B(-3, 2) == B(S(1) / 27, 9) and unchanged(Pow, B(-1, 1), B(1, 2)) and B(0, S(1) / 2) ** B(1, oo) == B(0, S(1) / 2) and B(0, 1) ** B(1, oo) == B(0, oo) and B(0, 2) ** B(1, oo) == B(0, oo) and B(0, oo) ** B(1, oo) == B(0, oo) and B(S(1) / 2, 1) ** B(1, oo) == B(0, oo) and B(S(1) / 2, 1) ** B(-oo, -1) == B(0, oo) and B(S(1) / 2, 1) ** B(-oo, oo) == B(0, oo) and B(S(1) / 2, 2) ** B(1, oo) == B(0, oo) and B(S(1) / 2, 2) ** B(-oo, -1) == B(0, oo) and B(S(1) / 2, 2) ** B(-oo, oo) == B(0, oo) and B(S(1) / 2, oo) ** B(1, oo) == B(0, oo) and B(S(1) / 2, oo) ** B(-oo, -1) == B(0, oo) and B(S(1) / 2, oo) ** B(-oo, oo) == B(0, oo) and B(1, 2) ** B(1, oo) == B(0, oo) and B(1, 2) ** B(-oo, -1) == B(0, oo) and B(1, 2) ** B(-oo, oo) == B(0, oo) and B(1, oo) ** B(1, oo) == B(0, oo) and B(1, oo) ** B(-oo, -1) == B(0, oo) and B(1, oo) ** B(-oo, oo) == B(0, oo) and B(2, oo) ** B(1, oo) == B(2, oo) and B(2, oo) ** B(-oo, -1) == B(0, S(1) / 2) and B(2, oo) ** B(-oo, oo) == B(0, oo)"},"spec":{"lhs":"test_AccumBounds_exponent()","rhs":"test_AccumBounds_exponent produces the expected output","over":{"base":"Any"},"name":"test_AccumBounds_exponent_correct"},"guarantee":"test_AccumBounds_exponent produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.calculus.tests.test_accumulationbounds.test_AccumBounds_exponent_correct","statement":"Path(test_AccumBounds_exponent(x), test_AccumBounds_exponent produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"126f136814c2f5f4"}
def test_AccumBounds_exponent():
    # base is 0
    z = 0**B(a, a + S.Half)
    assert z.subs(a, 0) == B(0, 1)
    assert z.subs(a, 1) == 0
    p = z.subs(a, -1)
    assert p.is_Pow and p.args == (0, B(-1, -S.Half))
    # base > 0
    #   when base is 1 the type of bounds does not matter
    assert 1**B(a, a + 1) == 1
    #  otherwise we need to know if 0 is in the bounds
    assert S.Half**B(-2, 2) == B(S(1)/4, 4)
    assert 2**B(-2, 2) == B(S(1)/4, 4)

    # +eps may introduce +oo
    # if there is a negative integer exponent
    assert B(0, 1)**B(S(1)/2, 1) == B(0, 1)
    assert B(0, 1)**B(0, 1) == B(0, 1)

    # positive bases have positive bounds
    assert B(2, 3)**B(-3, -2) == B(S(1)/27, S(1)/4)
    assert B(2, 3)**B(-3, 2) == B(S(1)/27, 9)

    # bounds generating imaginary parts unevaluated
    assert unchanged(Pow, B(-1, 1), B(1, 2))
    assert B(0, S(1)/2)**B(1, oo) == B(0, S(1)/2)
    assert B(0, 1)**B(1, oo) == B(0, oo)
    assert B(0, 2)**B(1, oo) == B(0, oo)
    assert B(0, oo)**B(1, oo) == B(0, oo)
    assert B(S(1)/2, 1)**B(1, oo) == B(0, oo)
    assert B(S(1)/2, 1)**B(-oo, -1) == B(0, oo)
    assert B(S(1)/2, 1)**B(-oo, oo) == B(0, oo)
    assert B(S(1)/2, 2)**B(1, oo) == B(0, oo)
    assert B(S(1)/2, 2)**B(-oo, -1) == B(0, oo)
    assert B(S(1)/2, 2)**B(-oo, oo) == B(0, oo)
    assert B(S(1)/2, oo)**B(1, oo) == B(0, oo)
    assert B(S(1)/2, oo)**B(-oo, -1) == B(0, oo)
    assert B(S(1)/2, oo)**B(-oo, oo) == B(0, oo)
    assert B(1, 2)**B(1, oo) == B(0, oo)
    assert B(1, 2)**B(-oo, -1) == B(0, oo)
    assert B(1, 2)**B(-oo, oo) == B(0, oo)
    assert B(1, oo)**B(1, oo) == B(0, oo)
    assert B(1, oo)**B(-oo, -1) == B(0, oo)
    assert B(1, oo)**B(-oo, oo) == B(0, oo)
    assert B(2, oo)**B(1, oo) == B(2, oo)
    assert B(2, oo)**B(-oo, -1) == B(0, S(1)/2)
    assert B(2, oo)**B(-oo, oo) == B(0, oo)


